    end

    if not self._isValidUser then
        return false
    end

    return true
end

function LSdkCpZd:_InternalIsNutaku()
    if LGameSettings.platformRegion == LRegionConst.AMERICA then
        local sId = tostring(self._sPackageId)
        if sId == "113" or sId == "114" then
            return true
        end
    end
    return false
end

---region currency

function LSdkCpZd:GetPayFormatValue(value)
    if self:IsDouYinGame() and LWxHelper.IsInIos() then
        return string.format("<sprite index=0> %s", tostring(value * 10))
    end
    if self:_InternalIsNutaku() then
        return string.format("N Gold %s", tostring(value))
    end
end

function LSdkCpZd:_GetCurrencyParams()
    --港币 HKD，符号：HK$
    --台币TWD ，符号：NT$
    --澳门MOP， 符号：MOP$
    --美元USD， 符号：$
    if LGameSettings.platformRegion == LRegionConst.KOREA then
        return "₩", "KRW"
    elseif LGameSettings.platformRegion == LRegionConst.CHINA then
        return "￥", "RMB"
    end

    if self:_InternalIsNutaku() then
        return "$", "NUT"
    end

    return "$", "USD"
end

function LSdkCpZd:_InitCurrency()
    local symbol, currency = self:_GetCurrencyParams()
    self._currencySymbol = symbol
    self._currency = currency
end

function LSdkCpZd:DoPayOrderRequest(payData, tgaData)
    --- 国内微信小程序，提审都不处理 单号：http://192.168.16.2:3002/issues/4146
    if gLGameLanguage:IsChinaRegion() and self:IsWXGame() and PRODUCT_G_VER ~= 0 then
        return
    end
    local payPointRef = gModelPay:GetWelfareProductPayPointRef(payData.payPointRefId)
    local produceCp = ""
    local payCurrency = "CNY"
    if payPointRef then
        local money
        produceCp, money, payCurrency = self:GetProductParam(payPointRef)
        local price = tonumber(money) or 0
        self._impl:CallTrack("OnPayOrderRequest", payData.goodsId, produceCp,price)
    end


    LSdkCpBase.DoPayOrderRequest(self, payData, tgaData)

end

function LSdkCpZd:GetCurrency()
    if string.isempty(self._currency) then
        self:_InitCurrency()
    end
    return self._currency
end

function LSdkCpZd:GetCurrencySymbol()
    if string.isempty(self._currencySymbol) then
        self:_InitCurrency()
    end
    return self._currencySymbol
end

