---@param payPointRef V_WelfareProductPayPointRef
function LSdkCpZd:GetProductParam(payPointRef)
    if LGameSettings.platformRegion == LRegionConst.KOREA then
        local produceCp = payPointRef.krwchannel
        local money = payPointRef.usdPayPoint
        return produceCp, money, "USD"
    elseif LGameSettings.platformRegion == LRegionConst.CHINA then
        local produceCp = payPointRef.rmbchannel
        local money = payPointRef.rmbPayPoint
        return produceCp, money, "RMB"
    else
        local produceCp = payPointRef.usdchannel
        local money = payPointRef.usdPayPoint
        return produceCp, money, "USD"
    end

end

function LSdkCpZd:OnInternalCreateOrderOk(orderData)
    local payData = orderData.payData
    local tgaData = orderData.tgaData
    local extraData = orderData.extraData
    local objJson = LxHttpHelper.CheckWebJson(CS.YXWebRet.ok, orderData.orderId)
    if (not objJson) then
        return
    end
    local sOutOrderNo = tostring(objJson.msg) --真实的订单id
    local sSign = objJson.cp_sign 

    local sMoney = tostring(payData.money) --价格
    local coinsAmount = payData.diamonds or 0
    local productName = payData.productName or ""
    local sProductDesc = productName
    local platformGoodsId = extraData.produceCp or "" --品项id
    local currency = "USD"

    local goodsId = tostring(payData.goodsId)
    --游戏货币与支付金额的比例
    local rate = 100
    if (coinsAmount > 0) then
        local moneyInt = tonumber(sMoney) or 0
        if moneyInt > 0 then
            rate = math.floor(coinsAmount / moneyInt)
        end
    end
    --是否允许充值成功后继续进行充值，0=是，其他=否，建议设置为0，只针对部分渠道生效
    local moreCharge = 0
    --游戏货币名称
    local gameGold = gModelItem:GetNameByRefId(ModelItem.ITEM_DIAMOND) or ""
    --支付类型，0=定额，1=不定额，只针对部分渠道生效
    local payType = 0
    local thirdPay = "true" --第三方支付开关，主要用于Google商店包，具体开启的条件请以运营要求为准，如不开启，可以不传。
    local thirdPayType = 1  -- 为网页支付类型：1为直购模式，0为普通模式；不传则为普通模式
    if PRODUCT_G_VER == 1 or PRODUCT_G_VER == 2 then
        thirdPay = "false"
        thirdPayType = 0
    end

    local packageId = tostring(self._sPackageId)
    if packageId == "1" or packageId == "11" then --1 资安包android  11 资安包苹果
        thirdPay = "false"
        thirdPayType = 0
    end

    if gLxTKData then
        tgaData.orderId = sOutOrderNo
        gLxTKData:OnPayTAReq(tgaData)
    end

    local sRoleId = gModelPlayer:GetPlayerId() or 0
    local sRoleName = gModelPlayer:GetPlayerName() or ""
    local sRoleLevel = tostring(tonumber(gModelPlayer:GetPlayerLv()) or 0)

    local sServerId = tostring(gLGameLogin:GetServerId() or 0)
    local sServerName = gLGameLogin:GetServerName() or ""

    local callBackStr = extraData.callBackInfo

    if CS.IsWebGL() then
        if LWxHelper.IsMiniGamePlatform() then
            self._impl:SendCpNativeMessage("Pay", platformGoodsId, sOutOrderNo, goodsId, sRoleId, sRoleName, sRoleLevel, sServerId, sServerName, sMoney, "", callBackStr,productName,productName, 0, 0)
        else
            self._impl:SendCpNativeMessage("Pay", platformGoodsId, sOutOrderNo)
        end
    else
        self._impl:SendCpNativeMessage("Pay", platformGoodsId, sOutOrderNo, goodsId, sRoleId, sRoleName, sRoleLevel, sServerId, sServerName, "0", "", callBackStr)
    end
end

