--是否由sdk条件来控制和谐版资源和裸露版资源显示
function LSdkCpZd:GetABTestRes()
    local isCtrlABTestRes = false
    local isBRes = false

    --if LGameSettings.platformRegion == LRegionConst.CHINA then
    --    ---国内全部和谐，不控制这
    --    return isCtrlABTestRes, isBRes
    --end

    if LGameSettings.ignoreShield then
        return isCtrlABTestRes, isBRes
    end
    local isChine = LGameSettings.platformRegion == LRegionConst.CHINA
    if isChine then
        return self:UpdateABTest()
    end

    local needCheck = CS.IsOSAndroid()
    if needCheck then
        -- 国内需要把这个改掉
        --android 由sdk控制裸露和谐
        isCtrlABTestRes = true
        --默认和谐版本
        isBRes = true

        if not isChine then
            self._isBlacklist = true
            --特定设备黑名单
            local brand = self:GetBrand()
            if not string.isempty(brand) then
                brand = string.lower(brand)
            end
            if brand == "google" then
                isBRes = true
                return isCtrlABTestRes, isBRes
            end
        end

        if self:CheckIsSpecificPuid() then
            isBRes = true
            if isChine then
                --- 黑名单功能：发行侧在每次审核的时候会从发行后台捞日志，捞到审核期间审核人员的PUID后提供给研发，研发在游戏后台添加记录，针对特定PUID，研发将PUID永久绑定，永久展示3深度和谐版本（同海外）
                LPlayerPrefs.GMSetLocalization(3)
                self._isBlacklist = true
            end
            return isCtrlABTestRes, isBRes
        end

        local afStatus = self:GetAfStatus()
        local isAfStatusInit = self:IsAfStatusInit()
        --非自然量裸露版本
        if isAfStatusInit and afStatus ~= "Organic" then
            isBRes = false
            return isCtrlABTestRes, isBRes
        end

        if isChine then
            --- Organic = 3深度和谐资源
            if isAfStatusInit and afStatus == "Organic" then
                isBRes = true
                self:ChangeOrganicResType()
            end
        end

        --预下载时间12月30日10点前开服的用户，标记未核心用户 , 注册时间是毫秒保存的
        --local regTime = (tonumber(self._sSdkRegTime) or 0) / 1000
        --local startTime = 0
        --local endTime = 1734969600
        --if regTime and regTime > 0 and (regTime >= startTime and regTime <= endTime)  then
        --    isBRes = false
        --    return isCtrlABTestRes, isBRes
        --end

        if self:IsPreRegister() then --注册用户，裸露版本
            isBRes = false
            return isCtrlABTestRes, isBRes
        end

    end
    return isCtrlABTestRes, isBRes
end

