function LSdkCpZd:GetSdkChnResourcesRef()
    local sId = tostring(self._sPackageId)
    local defaultRef
    local refs = GameTable.SdkChnResources
    for k,v in pairs(refs) do
        if v.name == sId then
            return v
        end
        if v.name == "101" then
            defaultRef = v
        end
    end
    ---  如果有包没有加的话，默认走101这个包的配置
    return defaultRef
end

function LSdkCpZd:SetSdkChnResourcesRef(ref)
    local resType = LPlayerPrefs.GetLocalization()
    ---@type boolean 是否使用了正确的资源类型
    local isInOnly = false
    local parameterOnly = string.split(ref.parameterOnly,",")
    for i,v in ipairs(parameterOnly) do
        if checknumber(v) == resType then
            isInOnly = true
        end
    end
    if not isInOnly then
        LPlayerPrefs.GMSetLocalization(ref.parameter)
    end
    if parameterOnly and #parameterOnly == 1 then
        -- 可修改的资源只有1个且等于parameter时，不允许通过其他方式修改资源版本
        local first = parameterOnly[1]
        if checknumber(first) == ref.parameter then
            --- 限制资源修改
            LPlayerPrefs.LimitResType(true)
        end
    end
end

