---# http://192.168.16.2:3002/issues/7001 
---# 【D多语言】国内参数资源逻辑优化（客户端）
function LSdkCpZd:UpdateABTest()
    -- 提审默认 1
    if PRODUCT_G_VER and PRODUCT_G_VER ~= 0 then
        local ref = self:GetSdkChnResourcesRef()
        self:SetSdkChnResourcesRef(ref)
        printInfoN("-----资源类型检测 " .. LPlayerPrefs.GetLocalization())
        return true, true
    end
    --- 国内改为全部都要检测
    return self:UpdateNormalABTest()
end

function LSdkCpZd:UpdateNormalABTest()
    local ref = self:GetSdkChnResourcesRef()
    local resources = ref.resources
    --- 0表示不走ab资源，1表示走ab资源
    if resources and resources == 0 then
        self:SetSdkChnResourcesRef(ref)
        return true,true
    end

    local isCtrlABTestRes,isBRes = true,true
    if self:IsBlacklist() then
        self:UpdateBlackListABTest()
    else
        if self:CheckIsSpecificPuid() then
            self._isBlacklist = true
            self:UpdateBlackListABTest()
        else
            --- 归因资源判断
            isCtrlABTestRes,isBRes = self:UpdateAfStatusABTest()
        end
    end
    return isCtrlABTestRes,isBRes
end

function LSdkCpZd:UpdateBlackListABTest()
    local ref = self:GetSdkChnResourcesRef()
    self:SetNoChangeLocalization(ref.blacklist)
end

function LSdkCpZd:UpdateAfStatusABTest()
    local ref = self:GetSdkChnResourcesRef()
    local platform = self:GetSdkPlatform() or ""
    platform = string.lower(platform)
    if string.find(platform,"guanwang") then
        self:SetNoChangeLocalization(ref.official)
        local officialRevise = ref.officialRevise
        if officialRevise and officialRevise > 0 then
            LPlayerPrefs.LimitResType(false)
        end
        LogWarn("官网包")
        if gModelPlayer then
            gModelPlayer:CheckNeedTranslateResType()
        end
        return true,true
    end

    if self:IsAfStatusInit() then
        self:SetSdkChnResourcesRef(ref)
        local needCheckOrganic = ref.attribution == 0
        local afStatus = self:GetAfStatus()
        local isOpenSex = gLGameLogin and gLGameLogin:IsOpenSex()
        if needCheckOrganic then
            if afStatus == "Organic" then
                --self:ChangeOrganicResType()
                LPlayerPrefs.GMSetLocalization(ref.nature)
            else
                if isOpenSex then
                    LPlayerPrefs.GMSetLocalization(ref.advertising)
                end
            end
        end
        if gModelPlayer then
            gModelPlayer:CheckNeedTranslateResType()
        end
        if afStatus then
            LogWarn("打印：afStatus = " .. afStatus .. ",屏蔽状态：" .. (isOpenSex and "开启" or "关闭"))
        end
        return true,isOpenSex
    else
        self:SetNoChangeLocalization(ref.notAttribution)
    end
    return true,gLGameLogin and gLGameLogin:IsOpenSex()
end

function LSdkCpZd:SetNoChangeLocalization(resType)
    LPlayerPrefs.LimitResType(false)
    ---- 没有接入归因时走的字段
    LPlayerPrefs.GMSetLocalization(resType)
    LPlayerPrefs.LimitResType(true)
end



