function LSdkCpZd:UploadRole(roleType)
    local roleId = gLGameLogin:GetPlayerId() or 0
    local roleName = ""
    local roleLevel = 0
    local sServerId = gLGameLogin:GetServerId() or "0"
    local sServerName = gLGameLogin:GetServerName() or ""
    local roleCTime = 0
    local loginTime = getInt(self._loginTime or 0)
    local logoutTime = 0
    local registerTime = 0
    local roleVip = 0
    local roleVipExp = 0
    if roleType == 1 then
        local playerData = gLGameLogin:GetPlayerData()
        if not playerData then return end
        roleName = playerData.name
        roleLevel = tonumber(playerData.level) or 0
        roleCTime = getInt(playerData.regTime or 0)
        logoutTime = getInt(playerData.lastLogoutTime or 0)
        registerTime = getInt(playerData.regTime or 0)
        roleVip = tonumber(playerData.vipLevel)
        --roleVipExp = tonumber(playerData.vipExp) or 0
    else
        roleName = gModelPlayer:GetPlayerName() or ""
        roleLevel = gModelPlayer:GetPlayerLv() or 0
        roleCTime = getInt(gModelPlayer:GetRegTime() or 0)
        logoutTime = getInt(gModelPlayer:GetLastLogoutTime() or 0)
        registerTime = getInt(gModelPlayer:GetRegTime() or 0)
        roleVip = gModelPlayer:GetVipLevel() or 0
        roleVipExp = gModelPlayer:GetVipExp() or 0
    end

    self._impl:SendCpNativeMessage("UploadRole", roleName, roleId, roleLevel, sServerName, sServerId)

    if roleType ~= 1 then
        --sdk_account_id        SDK账号id
        --role_id        角色id
        --role_name        角色昵称
        --server_name                区服名称
        --server_id                区服id
        --role_level        角色等级
        --role_vip_level        角色VIP等级
        --role_vip_exp                角色VIP经验
        --gold_ticket 代金券持有数量
        local ticket = gModelItem and gModelItem:GetNumByRefId(ModelItem.ITEM_GOLD_TICKET) or 0
        self:TrackEvent("vipPlayer_Info", "sdk_account_id", tostring(self._sUserId), "role_id", roleId, "role_name", roleName , "role_level", roleLevel, "role_vip_level", roleVip, "role_vip_exp", roleVipExp, "server_name", sServerName, "server_id", sServerId, "gold_ticket", ticket)
    end
end

