---订阅离线消息满
function LSdkCpZd:SubscribeTplMsg()
    local tplIds  = {"KFJUqIsU6ElEJtDK1G4TVDZgFY808gwA3aey3nBFil8"}
    local packageId = tostring(self._sPackageId)
    if packageId == "505" then
        tplIds  = {"QPaIIEMF1xbZJBqRFviLMBMrNKeRcAs7t3qDd0zrOEU"}
    end
    local types = {"离线收益订阅"}
    for i,v in ipairs(tplIds) do
        FireEvent(EventNames.SUBSCRIBE_POP_SHOW,v,types[i])
    end
    local tplIdsStr = table.concat(tplIds,",")
    local typesStr = table.concat(types,",")
    LogWarn("tplIdsStr = " .. tplIdsStr)
    LogWarn("typesStr = " .. typesStr)
    self._impl:SendCpNativeMessage("SubscribeTplMsg", tplIdsStr,typesStr)
end

function LSdkCpZd:OnSubscribeTplMsgResult(args)
    local isOk = toboolean(args[1])
    --- 是否打开订阅总开关，如果未打开的话，无法订阅任何通知，也无法调起订阅弹窗
    local mainSwitch = toboolean(args[2])
    if isOk and mainSwitch and args[3] then
        local openId = args[4]
        local addSubscribeInfos = {}
        local subSubscribeInfos = {}
        local jsonData = JSON.decode(args[3])
        for i,v in ipairs(jsonData) do
            local subscribeInfo
            if openId then
                --- doNotAskAgain(code=0才有):是否选择“总是保持以上选择，不再询问”
                --- doNotAskAgain为true时，微信不会再弹出订阅弹窗，而是直接返回当前设置
                --- time 字段为 -1 时，为 永久性通知
                subscribeInfo = {
                    touser = openId,
                    type = 1,
                    templateId = v.id,
                    time = toboolean(v.doNotAskAgain) and -1 or 0,
                }
            end
            -- accept：允许通知
            local bNotice = v.res == "accept"
            if bNotice then
                FireEvent(EventNames.SUBSCRIBE_POP_ACCEPT,v.id,v.type)
                if subscribeInfo then
                    table.insert(addSubscribeInfos,subscribeInfo)
                end
            else
                if subscribeInfo then
                    table.insert(subSubscribeInfos,subscribeInfo)
                end
            end
        end
        if #addSubscribeInfos > 0 then
            gModelSubscriber:OnWechatSubscribeReq(1,addSubscribeInfos)
        end
        if #subSubscribeInfos > 0 then
            gModelSubscriber:OnWechatSubscribeReq(3,subSubscribeInfos)
        end
    end
end

function LSdkCpZd:OnSubscribeTplMsgErrorResult(args)
    self:ShowSubscribeFailModal(args[2],args[3])
end

function LSdkCpZd:ShowSubscribeFailModal(tplIdsStr,typesStr)
    LogWarn(string.replace("ShowSubscribeFailModal tplIdsStr = #a1#,typesStr = #a2#",tplIdsStr,typesStr))
    local title = "开启失败"
    local content = "检测到您未开启订阅消息接收通知的权限，是否去设置里手动开启？"
    self._impl:SendCpNativeMessage("ShowSubscribeFailModal",title,content,tplIdsStr,typesStr)
end

function LSdkCpZd:OnShowSubscribeFailModal(args)
    local isOk = toboolean(args[1])
    local mainSwitch = toboolean(args[2])
    if isOk and mainSwitch and args[4] then
        local tplIdsStr,typesStr = args[5],args[6]
        local acceptMap = {}
        local rejectMap = {}
        -- 只有选择“总是保持以上选择，不再询问”的模板消息才会出现在itemSettings里
        local itemSettings = args[3]
        LogWarn(string.replace("OnShowSubscribeFailModal:arg[3] = #a1#,tplIdsStr = #a2#,typesStr = #a3#",itemSettings or "nil",tplIdsStr,typesStr))
        local jsonData = itemSettings and JSON.decode(itemSettings)
        if jsonData then
            for key,val in pairs(jsonData) do
                LogWarn(string.replace("key = #a1#,val = #a2#",key,val))
                if val == "accept" then
                    acceptMap[key] = true
                elseif val == "reject" then
                    rejectMap[key] = true
                end
            end
        end

        local openId = args[4]
        local addSubscribeInfos = {}
        local subSubscribeInfos = {}
        local tplIdsStrs = string.split(tplIdsStr,",")
        local typesStrs = string.split(typesStr,",")
        for i,id in ipairs(tplIdsStrs) do
            local doNotAskAgain = false
            if acceptMap[id] then
                doNotAskAgain = true
                FireEvent(EventNames.SUBSCRIBE_POP_ACCEPT,id,typesStrs[i])
            end
            local subscribeInfo = {
                touser = openId,
                type = 1,
                templateId = id,
                time = doNotAskAgain and -1 or 0,
            }
            if rejectMap[id] then
                table.insert(subSubscribeInfos,subscribeInfo)
            else
                table.insert(addSubscribeInfos,subscribeInfo)
            end
        end
        if #addSubscribeInfos > 0 then
            gModelSubscriber:OnWechatSubscribeReq(1,addSubscribeInfos)
        end
        if #subSubscribeInfos > 0 then
            gModelSubscriber:OnWechatSubscribeReq(3,subSubscribeInfos)
        end
    end
end

