function LSdkCpZd:_InternalStopWebQueryPuid()
    if self._webPuidQuery then
        self._webPuidQuery:Destroy()
        self._webPuidQuery = nil
    end
end
function LSdkCpZd:_InternalStopWebRecordPuid()
    if self._webPuidRecord then
        self._webPuidRecord:Destroy()
        self._webPuidRecord = nil
    end
end
function LSdkCpZd:_InternalStopWebBlackPuidQuery()
    if self._webBlackPuidQuery then
        self._webBlackPuidQuery:Destroy()
        self._webBlackPuidQuery = nil
    end
end
function LSdkCpZd:RecordPuid()
    if self._isRecordPuid then
       return
    end

    self._isRecordPuid = true

    local isRecord = toboolean(PJXCenter.GameMgr:GetGameEnvVar("RecordPuid"))
    if isRecord then
        return
    else
        PJXCenter.GameMgr:SetGameEnvVar("RecordPuid", "true")
    end

    local puid = self:GetDeviceID()
    if string.isempty(puid) then
        return
    end
    local type = 1
    local timestamp = GetTimestamp()

    self:_InternalStopWebRecordPuid()

    local webReq = LCpWebReq:New()
    self._webPuidRecord = webReq

    local sessionId = puid..tostring(type)..tostring(timestamp)
    local sign = CS.md5FromString(sessionId..LGameLogin.AuthKey)
    local tokenTbl = {
        "puid="..puid,
        "type="..type,
        "time="..timestamp,
        "sign="..sign
    }
    local paramPart = table.concat(tokenTbl, "&")
    local params = "/zd/puidVerify.do?"..paramPart

    local urlList = gLGameLogin:GetServicesUrlList()
    webReq:StartReq(urlList, params, function (ret, result)
        --if ret == CS.YXWebRet.ok then
        --    local code = tostring(result.code)
        --    if(code == "0") then
        --        self._isPuidRecorded = true
        --    end
        --end
        self:_InternalStopWebRecordPuid()
    end,false)
end

function LSdkCpZd:QueryPuid()
    if self._isQueryPuid then
       return
    end
    self._isQueryPuid = true
    local puid = self:GetDeviceID()
    if string.isempty(puid) then
        return
    end
    local type = 2
    local timestamp = GetTimestamp()

    self:_InternalStopWebQueryPuid()

    local webReq = LCpWebReq:New()
    self._webPuidQuery = webReq

    local sessionId = puid..tostring(type)..tostring(timestamp)
    local sign = CS.md5FromString(sessionId..LGameLogin.AuthKey)
    local tokenTbl = {
        "puid="..puid,
        "type="..type,
        "time="..timestamp,
        "sign="..sign
    }
    local paramPart = table.concat(tokenTbl, "&")
    local params = "/zd/puidVerify.do?"..paramPart

    local urlList = gLGameLogin:GetServicesUrlList()
    webReq:StartReq(urlList, params, function (ret, result)
        if ret == CS.YXWebRet.ok then
            local code = tostring(result.code)
            if(code == "0") then
                self._isPreRegister = true
                self:_InternalGotoCheckAbTest()
            end
        end
        self:_InternalStopWebQueryPuid()
    end,false)
end

function LSdkCpZd:QueryBlackPuid()
    if LGameSettings.platformRegion ~= LRegionConst.CHINA then return end
    if self._queryBlackPuid then return end
    self._queryBlackPuid = true

    local puid = self:GetDeviceID()
    if string.isempty(puid) then return end

    self:_InternalStopWebBlackPuidQuery()

    local webReq = LCpWebReq:New()
    self._webBlackPuidQuery = webReq

    local tokenTbl = { "puid="..puid, }
    local paramPart = table.concat(tokenTbl, "&")
    local params = "/zd/blackPuidVerify.do?"..paramPart
    local urlList = gLGameLogin:GetServicesUrlList()
    webReq:StartReq(urlList, params, function (ret, result)
        if ret == CS.YXWebRet.ok then
            local code = tostring(result.code)
            if code == "0" then
                self:SetBlackResType()
                --- 黑名单改成看的是提审服资源
                --LPlayerPrefs.GMSetLocalization(1)
            end
        end
        self:_InternalStopWebBlackPuidQuery()
    end,false)
end

function LSdkCpZd:SetBlackResType()
    self._isBlacklist = true
    self:UpdateABTest()
end

function LSdkCpZd:_InternalGotoCheckAbTest()
    if gLGameLogin then
        local playerLv = gModelPlayer and gModelPlayer:GetPlayerLv() or 0
        if playerLv == 0 then
            local playerData = gLGameLogin:GetPlayerData()
            if playerData then
                playerLv = tonumber(playerData.level) or 0
            end
        end
        gLGameLogin:CheckOpenSex(playerLv)
    end
end
