--on cp message
function LSdkCpZd:OnLoginResult(args)
    local isOk = toboolean(args[1])
    if isOk and args[2] and args[2] ~= "0" then
        self._sUserId = args[2]
        self._sToken = args[3]
        self._sSdkRegTime = args[4]

        LNativeHelper.SetReportUserId(self._sUserId)

        self._isValidUser = true
        self:LoginOk()

        --self:FetchPaymentItemDetails()

        if LGameSettings.platformRegion == LRegionConst.CHINA then
            self:QueryBlackPuid()
        else
            self:InitPushClientAlias()
            if not self._isPreRegister and not (self:GetAfStatus() ~= "Organic") then
                self:QueryPuid()
            end
        end
        if self:IsWXGame() then
            --- 微小 实名认证
            self:GetWXIdInfo()
        else
            self:GetWebIconSceneEntryInfo()
        end

        --self:ReportFeedScene()
    else
        self._sUserId = ""
        self._sToken = ""

        self:LoginFailure()
    end
end

