function LSdkCpZd:OnInitResult(args)
    local isOk = toboolean(args[1])
    if LOG_INFO_ENABLED then
        printInfoN2("zdsdk", "Lua InitResult +++" .. tostring(isOk))
    end
    self._isInit = isOk
    FireEvent(EventNames.SDK_INIT_OK)
    local statusCode = tonumber(args[2])
    local initCount = self._initCount or 0
    initCount = initCount + 1
    self._initCount = initCount
    if gLxPatchCtrl and statusCode and statusCode ~= 0 and not isOk then
        if self:IsWXGame() or self:IsDouYinGame() or self:IsBiliGame() then
            gLxPatchCtrl:ShowSysTips(18, tostring(statusCode), function(btnType)
                if btnType == 1 then
                    QuitGame()
                elseif btnType == 2 then
                    RestartGame()
                end
            end, nil)
        else
            if initCount <= 2 then
                --失败了重初始化两次
                LxTimer.DelayTimeCall(function()
                    self:Init()
                end, 0.5)
                return
            end
            gLxPatchCtrl:ShowSysTips(18, tostring(statusCode), function(btnType)
                if btnType == 1 then
                    QuitGame()
                elseif btnType == 2 then
                    self:Init()
                end
            end, nil)
        end
    end

    if isOk then
        if CS.IsOSOpenHarmony() then
            if LOG_INFO_ENABLED then
                printInfoN("归因状态 鸿蒙归因初始化")
            end
            self:IsAfStatusInit()
        end
        self:CheckScene()
        if self:IsSupportShortCut() then
            self:CheckShortCut()
        end

    end
end

