function LSdkCpZd:OnBindMobileResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        GF.ShowMessage(ccClientText(15070))
    else
        local code = checknumber(args[3])
        if code and code > 0 then
            if code == 5001 then
                -- 验证码有误/验证失败
                GF.ShowMessage(ccClientText(47614))
            elseif code == 5002 then
                -- 当前账号已经绑定过手机号
                GF.ShowMessage(ccClientText(47615))
            elseif code == 5004 then
                -- 该手机号已经被其他账号绑定
                GF.ShowMessage(ccClientText(47616))
            end
        end
    end
    local phone = isOk and checknumber(args[2])
    FireEvent(EventNames.SDK_ACCOUNTBIND_RESULT,isOk,phone)
end


function LSdkCpZd:OnMobileAuthCodeResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        GF.ShowMessage(ccClientText(47613))
        local nextCodeGetTime = GetTimestamp() + 60
        LPlayerPrefs.SetGetCodeCDTime(nextCodeGetTime)
    else
        local code = checknumber(args[2])
        if code and code > 0 then
            if code == 5029 then
                --手机号格式有误
                GF.ShowMessage(ccClientText(47617))
            end
        end
    end
    FireEvent(EventNames.SDK_MOBILE_AUTHCODE_RESULT)
end

