function LSdkCpZd:OnAfStatusResult(args)
    local isInit = toboolean(args[1])
    self._isAfStatusInit = isInit
    local afStatus = args[2]
    self._afStatus = afStatus
    if LOG_INFO_ENABLED then
        if isInit then
            printInfoN("归因状态 成功 afStatus = : "..afStatus)
        else
            printInfoN("归因状态 失败")
        end
    end
    self:UpdateABTest()

    if self._isAfStatusInit and afStatus ~= "Organic" and self:IsLogin() then
        if LGameSettings.platformRegion == LRegionConst.CHINA then
        else
            self:RecordPuid()
        end
    end
    self:_InternalGotoCheckAbTest()
end

