function LSdkCpZd:OpenPrivacyPolicy()
    local url = nil
    local sdkPlatform = self:GetSdkPlatform()
    if sdkPlatform == "OPPO_CN" then
        url = GameTable.InnerActivityConfigRef.privacyReward3
    elseif sdkPlatform == "VIVO_CN" then
        url = GameTable.InnerActivityConfigRef.privacyReward4
    elseif sdkPlatform == "XIAOMI_CN" then
        url = GameTable.InnerActivityConfigRef.privacyReward1
    elseif sdkPlatform == "HUAWEI_CN" then
        url = GameTable.InnerActivityConfigRef.privacyReward2
    else
        url = GameTable.InnerActivityConfigRef.privacyReward5
    end
    if string.isempty(url) then return end
    CS.UApplication.OpenURL(url)
end

