local SceneEntry_WebIcon = "WebIcon"
local SceneEntry_PaidPopUp = "PaidPopUp"

function LSdkCpZd:GetSceneEntryInfo(args)
    local scene = args[1]
    return self._impl:SendCpNativeMessage("GetSceneEntryInfo",scene)
end

function LSdkCpZd:OnGetSceneEntryInfoResult(args)
    local isOk = toboolean(args[1])
    local scene = args[2]
    if isOk then
        local showInfo
        local bShow = toboolean(args[8])
        if bShow then
            local link = args[7]
            if not string.isempty(link) then
                showInfo = {
                    title = args[3],
                    content = args[4],
                    imgUrl = args[5],
                    btnText = args[6],
                    link = link,
                }
            end
        else
        end
        if scene == SceneEntry_WebIcon then
            local hasWebIconInfo = showInfo ~= nil
            self._hasWebIconInfo = hasWebIconInfo
            self._webIconInfo = showInfo
        elseif scene == SceneEntry_PaidPopUp then
            if showInfo then
                GF.OpenWnd("UIRechargeBenefits",{showInfo = showInfo})
            end
        end
    else
        if scene == SceneEntry_WebIcon then
            self._hasWebIconInfo = false
            self._webIconInfo = nil
        end
    end
    self:DoSceneEntryCB()
    FireEvent(EventNames.SDK_GETSCENEENTRYINFO_RESULT,isOk,scene)
end

--- WebIcon 调用时机在游戏登录成功后
function LSdkCpZd:GetWebIconSceneEntryInfo()
    if LGameSettings.platformRegion == LRegionConst.CHINA then
        self:GetSceneEntryInfo({SceneEntry_WebIcon})
    end
end

--- PaidPopuUp 调用时机在支付成功后
--- 20260128：修改为支付成功且发货成功调用
function LSdkCpZd:GetPaidPopUpSceneEntryInfo()
    if LGameSettings.platformRegion == LRegionConst.CHINA then
        self:GetSceneEntryInfo({SceneEntry_PaidPopUp})
    end
end

function LSdkCpZd:GetWebIconInfo()
    if self._hasWebIconInfo then
        return self._webIconInfo
    end
end

function LSdkCpZd:CheckHasSceneEntryInfo(checkWebIconType)
    self._checkWebIconType = checkWebIconType
    if checkWebIconType == 1 then
        self:GetWebIconSceneEntryInfo()
    elseif checkWebIconType == 2 then
        self:GetPaidPopUpSceneEntryInfo()
    end
end

function LSdkCpZd:DoSceneEntryCB()
    if not self._checkWebIconType then return end
    
    local checkWebIconType = self._checkWebIconType
    self._checkWebIconType = nil
    if checkWebIconType == 1 then
        local webIconInfo = self:GetWebIconInfo()
        if webIconInfo then
            GF.OpenWnd("UIRechargeBenefits",{showInfo = webIconInfo})
        end
    end
end
