function LSdkCpZd:CheckIsFeedScene()
    local bFeedScene = self:IsFeedScene()
    if not bFeedScene then return false end
    
    if self._isFirstEnterFeedScene then
        return false
    end
    LogWarn("检测成功 直流")
    self._isFirstEnterFeedScene = true
    return bFeedScene
end

function LSdkCpZd:CheckCanJumpFeedScene()
    if not self._isFirstEnterFeedScene then return end
    if self._isFirstJumpAdventure then return end
    --if not gModelFunctionOpen:CheckIsShow(10210001) then 
    --    return 
    --end
--[[    if gModelGuide:IsInGuide() then
        self._isFirstJumpAdventure = true
        self._isOpenAward = true
        return 
    end]]
    LogWarn("检测成功 跳转至直流")
    self._isFirstJumpAdventure = true
    local isJump = false
    local feed_game_scene = self:GetFeedGameScene()
    if feed_game_scene and feed_game_scene > 0 then
        if feed_game_scene == 1 then
            isJump = true
            FireEvent(EventNames.CHANGE_MAIN_BTN, LMainBtnIndexConst.ADVENTURE,{["UIGjAward"] = true},true)
        elseif feed_game_scene == 2 then
            isJump = true
            FireEvent(EventNames.CHANGE_MAIN_BTN, LMainBtnIndexConst.CITY,{["UIGBuy"] = true},true)
        elseif feed_game_scene == 3 then
            local feed_game_extra = self:GetFeedGameExtra()
            local jumpWnd = gModelActivity and gModelActivity:CheckNeedJumpFeed(feed_game_extra)
            if not string.isempty(jumpWnd) then
                LogWarn("跳转至：" .. jumpWnd)
                isJump = true
                FireEvent(EventNames.CHANGE_MAIN_BTN, LMainBtnIndexConst.CITY,{[jumpWnd] = true},true)
            else
                LogWarn("没有检测到对应界面，feed_game_extra = " .. feed_game_extra)
            end
        end
    end
    if not isJump then return end
    return true
end

function LSdkCpZd:CheckNeedOpenFeedSceneUI()
    if not self._isFirstJumpAdventure then return end
    if self._isOpenAward then return end
    LogWarn("检测成功 跳转到直流界面")
    self._isOpenAward = true

    local wndName
    local bJump = false
    local feed_game_scene = self:GetFeedGameScene()
    if feed_game_scene and feed_game_scene > 0 then
        if feed_game_scene == 1 then
            if gModelGuide then
                gModelGuide:SetJumpFeedScene()
            else
                LogWarn("检测成功 模块未初始化")
            end
            bJump = true
            wndName = "UIGjAward"
            GF.OpenWndTop(wndName,{feedOpen = true})
        elseif feed_game_scene == 2 then
            if gModelGuide then
                gModelGuide:SetJumpFeedScene()
            else
                LogWarn("检测成功 模块未初始化")
            end
            bJump = true
            wndName = "UIGBuy"
            GF.OpenWndTop(wndName,{feedOpen = true})
        elseif feed_game_scene == 3 then
            local feed_game_extra = self:GetFeedGameExtra()
            local jumpWnd,extraData
            if gModelActivity then
                jumpWnd,extraData = gModelActivity:CheckNeedJumpFeed(feed_game_extra)
            end
            if not string.isempty(jumpWnd) and extraData then
                if gModelGuide then
                    gModelGuide:SetJumpFeedScene()
                else
                    LogWarn("检测成功 模块未初始化")
                end
                bJump = true
                wndName = jumpWnd
                LogWarn("检测成功 跳转到" .. jumpWnd)

                local wndData = {
                    feedOpen = true,
                    sid = extraData.sid,
                    targetId = extraData.subPage,
                }
                GF.OpenWndTop(jumpWnd,wndData)
                --if gModelGuide:IsJumpFeedScene() then
                --else
                --    gModelGeneral:InsertTimeLimitWndEx({
                --        uiName = wndName,
                --        para = wndData
                --    })
                --end
            end
        end
    end
    if not bJump then
		FireEvent(EventNames.ON_CHECK_SUBSCRIBE_FEED_CLEANTAR)
        return
    end

    self:ReportFeedScene()
    return true,wndName
end

function LSdkCpZd:IsProductBlockRecharging()
    if gLGameLanguage:IsChinaRegion() and self:IsWXGame() then
        if PRODUCT_G_VER ~= 0 then
            return true
        end
    end
end

return LSdkCpZd
